{
    char S[1000001];
    scanf("%s", S);
    int len = strlen(S);
    int i = 0;
    int j = 0;
    int count = 1;
    int flag = 0;
    while (i < len)
    {
        while (i < len && S[i] == S[j])
        {
            i++;
            count++;
        }
        if (count > 1)
        {
            flag = 1;
            break;
        }
        j = i;
        count = 1;
    }
    if (flag == 1)
    {
        printf("NO\n");
    }
    else
    {
        printf("YES\n");
    }
}

