code.Java:
public class Main
{
    public static void main(String[] args)
    {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        scanner.nextLine();
        while (T-- > 0)
        {
            String S = scanner.nextLine();
            int len = S.length();
            int i = 0;
            int j = 0;
            int count = 1;
            int flag = 0;
            while (i < len)
            {
                while (i < len && S.charAt(i) == S.charAt(j))
                {
                    i++;
                    count++;
                }
                if (count > 1)
                {
                    flag = 1;
                    break;
                }
                j = i;
                count = 1;
            }
            if (flag == 1)
            {
                System.out.println("NO");
            }
            else
            {
                System.out.println("YES");
            }
        }
    }
}

